import openpyxl

def process_spreadsheet(input_path, output_path):
    wb = openpyxl.load_workbook(input_path)
    sheet = wb.active

    data = []
    for row in range(1, sheet.max_row + 1):
        item = sheet.cell(row=row, column=1).value
        name = sheet.cell(row=row, column=2).value
        ref = sheet.cell(row=row, column=3).value

        if name is None or str(name).strip() == "":
            continue

        if str(item).strip().upper() == "ITEM" and str(name).strip().upper() == "NAME":
            continue

        data.append({'row': row, 'item': item, 'name': name, 'ref': ref})

    seen = set()
    unique_data = []
    for row in data:
        key = (str(row['name']).strip(), str(row['ref']).strip())
        if key not in seen:
            seen.add(key)
            unique_data.append(row)

    j_list = []
    for row in range(1, sheet.max_row + 1):
        val = sheet.cell(row=row, column=10).value
        if val is not None and str(val).strip() != "":
            val_str = str(val).strip()
            if val_str.upper() == "LIST":
                continue
            if val_str not in j_list:
                j_list.append(val_str)

    if not j_list:
        unique_data.sort(key=lambda x: str(x['name']).strip().upper())
    else:
        def sort_key(x):
            name = str(x['name']).strip()
            if name in j_list:
                return (0, j_list.index(name), x['row'])
            else:
                return (1, 0, x['row'])
        unique_data.sort(key=sort_key)

    for row in range(2, 21):
        sheet.cell(row=row, column=6).value = None
        sheet.cell(row=row, column=7).value = None
        sheet.cell(row=row, column=8).value = None

    for i, row_data in enumerate(unique_data):
        target_row = i + 2
        if target_row > 20:
            break
        sheet.cell(row=target_row, column=6).value = row_data['item']
        sheet.cell(row=target_row, column=7).value = row_data['name']
        sheet.cell(row=target_row, column=8).value = row_data['ref']

    wb.save(output_path)

if __name__ == "__main__":
    process_spreadsheet('/app/spreadsheets/1_22-47_input.xlsx', '/app/output/1_22-47_output.xlsx')
